function getCardIcon(title: string, className?: string) {
  switch (title.toLowerCase()) {
    case "projects":
      return <ProjectsIcon className={className} />
    case "designs":
      return <DesignsIcon className={className} />
    case "blog":
      return <BlogIcon className={className} />
    default:
      return null
  }
}

export function Gallery({ mode = "default", ...props }: BentoCardProps) {
  const router = useRouter()
  const [opened, setOpened] = useState(false)
  const [active, setActive] = useState<number | null>(1)
  const [introAnimation, setIntroAnimation] = useState(true)

  useEffect(() => {
    const timeout = setTimeout(() => {
      setIntroAnimation(false)
    }, 900)

    return () => clearTimeout(timeout)
  }, [])

  if (mode === "compact") {
    return (
      <BentoGridItem
        {...props}
        className="grid h-full w-full grid-cols-3 gap-3 !overflow-visible border-none bg-transparent !p-0 shadow-none hover:shadow-none sm:gap-4"
      >
        {cards.map((card) => (
          <Link
            key={card.title}
            href={card.href}
            className={`group flex flex-col justify-between rounded-[30px] border p-4 text-left shadow-sm transition-all duration-300 hover:scale-[1.02] ${card.bg} border-border/40 hover:border-border/85`}
            data-cursor="pointer"
          >
            <div className="flex items-start justify-between gap-2">
              <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-[14px] bg-foreground/10 p-2">
                {getCardIcon(card.title, "h-full w-full")}
              </div>
              <div className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-background/80 text-foreground transition-transform group-hover:translate-x-0.5 group-hover:-translate-y-0.5">
                <ArrowUpRightIcon size={12} />
              </div>
            </div>

            <div className="mt-2.5 space-y-0.5">
              <p className="font-mono text-[8px] tracking-[0.2em] uppercase opacity-60">
                {card.role}
              </p>
              <h3 className="text-base font-bold tracking-tight">
                {card.title}
              </h3>
              <p className="line-clamp-1 text-[10px] leading-snug opacity-75">
                {card.description}
              </p>
            </div>
          </Link>
        ))}
      </BentoGridItem>
    )
  }

  return (
    <BentoGridItem
      {...props}
      className="relative isolate flex items-center justify-center overflow-visible border-none bg-transparent !p-0 [contain:layout] hover:shadow-none"
    >
      {(delay: number) => (
        <motion.div
          onHoverStart={() => setOpened(true)}
          onHoverEnd={() => {
            setOpened(false)
            setActive(1)
          }}
          className="absolute flex h-full min-h-[320px] items-center justify-center"
        >
          {cards.map((card, i) => {
            const isActive = active === i

            return (
              <motion.button
                key={card.title}
                data-cursor="link"
                onHoverStart={() => {
                  setOpened(true)
                  setActive(i)
                }}
                onClick={() => router.push(card.href)}
                initial={{
                  x: 0,
                  y: 40,
                  rotate: 0,
                  scale: 0.8,
                  opacity: 0,
                }}
                animate={{
                  x: opened ? card.x : card.x * 0.65,
                  y: opened ? (isActive ? -18 : 10) : 10,
                  rotate: opened ? card.rotate : card.rotate * 0.4,
                  scale: opened ? (isActive ? 1 : 0.92) : 0.9,
                  opacity: 1,
                }}
                transition={{
                  type: "spring",
                  stiffness: 180,
                  damping: 18,
                  delay: introAnimation ? card.delay + delay : 0,
                }}
                className={`absolute mb-5 flex h-[240px] w-[185px] flex-col justify-between rounded-[30px] border border-border/50 p-4 shadow-2xl ${card.bg}`}
                style={{
                  zIndex: isActive ? 50 : i,
                }}
              >
                <div className="flex items-start justify-between">
                  <div className="flex h-20 w-20 items-center justify-center rounded-[24px] bg-foreground/10 p-3.5">
                    {getCardIcon(card.title, "h-full w-full")}
                  </div>

                  <div
                    className={`flex h-10 w-10 items-center justify-center rounded-full ${
                      isActive
                        ? "bg-foreground text-background"
                        : "bg-background text-foreground"
                    }`}
                  >
                    <ArrowUpRightIcon size={18} />
                  </div>
                </div>

                <div className="space-y-1 text-left">
                  <p className="text-xs opacity-60">{card.role}</p>

                  <h2 className="text-3xl font-semibold tracking-tight">
                    {card.title}
                  </h2>

                  <p className="text-sm opacity-75">{card.description}</p>
                </div>
              </motion.button>
            )
          })}
        </motion.div>
      )}
    </BentoGridItem>
  )
}

